{
  "name": "Zenith AI Expense Tracker",
  "description": "A high-end personal finance manager with glassmorphism UI, interactive charts, and Gemini-powered financial insights."
}

export type TransactionType = 'Income' | 'Expense' | 'Investment';

export interface Transaction {
  id: string;
  name: string;
  amount: number;
  category: string;
  date: string;
  type: TransactionType;
}

export interface UserProfile {
  name: string;
  initialBalance: number;
}

export const CATEGORIES = [
  'Housing',
  'Food',
  'Transport',
  'Health',
  'Entertainment',
  'Shopping',
  'Utilities',
  'Education',
  'Salary',
  'Dividends',
  'Gift',
  'Stocks',
  'Crypto',
  'Real Estate',
  'Other'
];

export interface AITip {
  title: string;
  advice: string;
  priority: 'High' | 'Medium' | 'Low';
}

import { GoogleGenAI, Type } from "@google/genai";
import { Transaction, AITip } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY! });

export const getFinancialTips = async (transactions: Transaction[]): Promise<AITip[]> => {
  if (transactions.length === 0) {
    return [{
      title: "Start Tracking",
      advice: "Add your first transaction to get personalized AI financial advice.",
      priority: "Low"
    }];
  }

  const summary = transactions.reduce((acc, t) => {
    acc[t.category] = (acc[t.category] || 0) + (t.type === 'Expense' ? t.amount : 0);
    return acc;
  }, {} as Record<string, number>);

  const prompt = `Based on the following spending summary by category: ${JSON.stringify(summary)}. 
  Provide 3 concise, actionable financial tips for the user. 
  Focus on identifying high spending areas and suggesting ways to save or invest better.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              advice: { type: Type.STRING },
              priority: { type: Type.STRING, enum: ["High", "Medium", "Low"] }
            },
            required: ["title", "advice", "priority"]
          }
        }
      }
    });

    return JSON.parse(response.text || "[]");
  } catch (error) {
    console.error("Error fetching AI tips:", error);
    return [{
      title: "Keep Saving",
      advice: "Try to set aside 20% of your income for long-term investments.",
      priority: "Medium"
    }];
  }
};

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) throw new Error("Root element not found");

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Plus, 
  Wallet, 
  TrendingUp, 
  TrendingDown, 
  Download, 
  Trash2, 
  Sparkles, 
  User, 
  PieChart as PieChartIcon,
  BarChart3,
  Search,
  CheckCircle2,
  AlertCircle
} from 'lucide-react';
import { 
  PieChart, Pie, Cell, ResponsiveContainer, Tooltip as RechartsTooltip,
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Legend
} from 'recharts';
import * as XLSX from 'xlsx';
import { Transaction, TransactionType, CATEGORIES, AITip } from './types';
import { getFinancialTips } from './geminiService';

const COLORS = ['#6366f1', '#10b981', '#f43f5e', '#f59e0b', '#8b5cf6', '#ec4899', '#06b6d4', '#84cc16'];

const App: React.FC = () => {
  // State
  const [userName, setUserName] = useState<string>(() => localStorage.getItem('zenith_user') || 'Zenith User');
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('zenith_txs');
    return saved ? JSON.parse(saved) : [];
  });
  const [aiTips, setAiTips] = useState<AITip[]>([]);
  const [isLoadingTips, setIsLoadingTips] = useState(false);
  const [isAddingTx, setIsAddingTx] = useState(false);

  // Form State
  const [formData, setFormData] = useState({
    name: '',
    amount: '',
    category: CATEGORIES[0],
    date: new Date().toISOString().split('T')[0],
    type: 'Expense' as TransactionType
  });

  // Persist Data
  useEffect(() => {
    localStorage.setItem('zenith_txs', JSON.stringify(transactions));
    localStorage.setItem('zenith_user', userName);
  }, [transactions, userName]);

  // Fetch AI Tips on mount and when significant changes happen
  useEffect(() => {
    const fetchTips = async () => {
      setIsLoadingTips(true);
      const tips = await getFinancialTips(transactions);
      setAiTips(tips);
      setIsLoadingTips(false);
    };

    // Fetch only if we have transactions or initial state
    const timer = setTimeout(fetchTips, 1000);
    return () => clearTimeout(timer);
  }, [transactions.length]);

  // Derived Stats
  const stats = useMemo(() => {
    const income = transactions
      .filter(t => t.type === 'Income')
      .reduce((sum, t) => sum + t.amount, 0);
    const expenses = transactions
      .filter(t => t.type === 'Expense')
      .reduce((sum, t) => sum + t.amount, 0);
    const investments = transactions
      .filter(t => t.type === 'Investment')
      .reduce((sum, t) => sum + t.amount, 0);

    return {
      balance: income - expenses - investments,
      investments,
      totalWealth: income - expenses,
      expenses
    };
  }, [transactions]);

  const categoryData = useMemo(() => {
    const map: Record<string, number> = {};
    transactions.filter(t => t.type === 'Expense').forEach(t => {
      map[t.category] = (map[t.category] || 0) + t.amount;
    });
    return Object.entries(map).map(([name, value]) => ({ name, value }));
  }, [transactions]);

  const trendData = useMemo(() => {
    const last7Days = Array.from({ length: 7 }, (_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - i);
      return d.toISOString().split('T')[0];
    }).reverse();

    return last7Days.map(date => {
      const dayTxs = transactions.filter(t => t.date === date);
      return {
        date: date.split('-').slice(1).join('/'),
        Expenses: dayTxs.filter(t => t.type === 'Expense').reduce((s, t) => s + t.amount, 0),
        Income: dayTxs.filter(t => t.type === 'Income').reduce((s, t) => s + t.amount, 0),
      };
    });
  }, [transactions]);

  // Handlers
  const handleAddTransaction = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.amount) return;

    const newTx: Transaction = {
      id: crypto.randomUUID(),
      name: formData.name,
      amount: parseFloat(formData.amount),
      category: formData.category,
      date: formData.date,
      type: formData.type
    };

    setTransactions([newTx, ...transactions]);
    setFormData({
      ...formData,
      name: '',
      amount: ''
    });
    setIsAddingTx(false);
  };

  const deleteTransaction = (id: string) => {
    setTransactions(transactions.filter(t => t.id !== id));
  };

  const exportToExcel = () => {
    const ws = XLSX.utils.json_to_sheet(transactions);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Transactions");
    XLSX.writeFile(wb, `${userName}_Expenses.xlsx`);
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 lg:py-12">
      {/* Header Section */}
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-6">
        <div className="flex items-center gap-4">
          <div className="p-3 rounded-2xl bg-indigo-500/20 glass border border-indigo-500/30">
            <User className="text-indigo-400 w-8 h-8" />
          </div>
          <div>
            <input 
              className="bg-transparent text-2xl font-bold focus:outline-none focus:ring-1 focus:ring-indigo-500 rounded px-1 w-full max-w-[250px]"
              value={userName}
              onChange={(e) => setUserName(e.target.value)}
              placeholder="Your Name"
            />
            <p className="text-slate-400 text-sm">Welcome back to your financial sanctuary.</p>
          </div>
        </div>
        <div className="flex gap-3 w-full md:w-auto">
          <button 
            onClick={exportToExcel}
            className="flex-1 md:flex-none flex items-center justify-center gap-2 px-4 py-2.5 rounded-xl glass-card text-sm font-medium hover:bg-white/10 transition-all border border-white/10"
          >
            <Download size={18} />
            Export Data
          </button>
          <button 
            onClick={() => setIsAddingTx(true)}
            className="flex-1 md:flex-none flex items-center justify-center gap-2 px-6 py-2.5 rounded-xl bg-indigo-600 hover:bg-indigo-500 text-white text-sm font-semibold shadow-lg shadow-indigo-600/20 transition-all"
          >
            <Plus size={18} />
            Add Record
          </button>
        </div>
      </header>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-10">
        <div className="glass p-6 rounded-3xl relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform">
            <Wallet size={80} />
          </div>
          <p className="text-indigo-300 text-sm font-medium mb-1">Current Balance</p>
          <h2 className="text-3xl font-bold">${stats.balance.toLocaleString()}</h2>
          <div className="mt-4 flex items-center gap-2 text-emerald-400 text-xs font-semibold">
            <TrendingUp size={14} />
            <span>Active Funds</span>
          </div>
        </div>
        <div className="glass p-6 rounded-3xl relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform">
            <TrendingUp size={80} />
          </div>
          <p className="text-amber-300 text-sm font-medium mb-1">Investment Portfolio</p>
          <h2 className="text-3xl font-bold">${stats.investments.toLocaleString()}</h2>
          <div className="mt-4 flex items-center gap-2 text-amber-400 text-xs font-semibold">
            <CheckCircle2 size={14} />
            <span>Growth Assets</span>
          </div>
        </div>
        <div className="glass p-6 rounded-3xl relative overflow-hidden group bg-emerald-500/5">
          <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform">
            <Sparkles size={80} />
          </div>
          <p className="text-emerald-300 text-sm font-medium mb-1">Total Net Worth</p>
          <h2 className="text-3xl font-bold text-emerald-400">${stats.totalWealth.toLocaleString()}</h2>
          <div className="mt-4 flex items-center gap-2 text-emerald-300/60 text-xs font-semibold">
            <Sparkles size={14} />
            <span>Financial Freedom Score: High</span>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Main Content Area */}
        <div className="lg:col-span-8 space-y-8">

          {/* Charts Section */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="glass p-6 rounded-3xl">
              <div className="flex items-center gap-2 mb-6">
                <PieChartIcon className="text-indigo-400" size={20} />
                <h3 className="font-semibold text-lg">Spending Mix</h3>
              </div>
              <div className="h-[250px]">
                {categoryData.length > 0 ? (
                  <ResponsiveContainer width="100%" height="100%">
                    <PieChart>
                      <Pie
                        data={categoryData}
                        innerRadius={60}
                        outerRadius={80}
                        paddingAngle={5}
                        dataKey="value"
                      >
                        {categoryData.map((entry, index) => (
                          <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                        ))}
                      </Pie>
                      <RechartsTooltip 
                        contentStyle={{ backgroundColor: '#1e1b4b', border: 'none', borderRadius: '12px' }}
                        itemStyle={{ color: '#fff' }}
                      />
                    </PieChart>
                  </ResponsiveContainer>
                ) : (
                  <div className="h-full flex flex-col items-center justify-center text-slate-500 text-sm italic">
                    <p>No expense data to visualize</p>
                  </div>
                )}
              </div>
            </div>

            <div className="glass p-6 rounded-3xl">
              <div className="flex items-center gap-2 mb-6">
                <BarChart3 className="text-indigo-400" size={20} />
                <h3 className="font-semibold text-lg">7-Day Activity</h3>
              </div>
              <div className="h-[250px]">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={trendData}>
                    <CartesianGrid strokeDasharray="3 3" stroke="#ffffff10" vertical={false} />
                    <XAxis dataKey="date" stroke="#94a3b8" fontSize={12} tickLine={false} axisLine={false} />
                    <YAxis stroke="#94a3b8" fontSize={12} tickLine={false} axisLine={false} />
                    <RechartsTooltip 
                      cursor={{ fill: 'rgba(255,255,255,0.05)' }}
                      contentStyle={{ backgroundColor: '#1e1b4b', border: 'none', borderRadius: '12px' }}
                    />
                    <Legend />
                    <Bar dataKey="Income" fill="#10b981" radius={[4, 4, 0, 0]} />
                    <Bar dataKey="Expenses" fill="#f43f5e" radius={[4, 4, 0, 0]} />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </div>
          </div>

          {/* Transactions List */}
          <div className="glass rounded-3xl overflow-hidden">
            <div className="p-6 border-b border-white/10 flex justify-between items-center">
              <h3 className="font-semibold text-lg">Recent Transactions</h3>
              <div className="relative group">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 group-hover:text-slate-400 transition-colors" size={16} />
                <input 
                  type="text" 
                  placeholder="Quick search..." 
                  className="bg-white/5 border border-white/10 rounded-full pl-10 pr-4 py-1.5 text-sm focus:outline-none focus:ring-1 focus:ring-indigo-500 w-48 transition-all focus:w-64"
                />
              </div>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="text-slate-400 text-xs uppercase tracking-wider bg-white/5">
                  <tr>
                    <th className="px-6 py-4 font-semibold">Description</th>
                    <th className="px-6 py-4 font-semibold">Category</th>
                    <th className="px-6 py-4 font-semibold">Date</th>
                    <th className="px-6 py-4 font-semibold">Amount</th>
                    <th className="px-6 py-4 font-semibold">Action</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-white/5">
                  {transactions.length > 0 ? (
                    transactions.map((tx) => (
                      <tr key={tx.id} className="group hover:bg-white/5 transition-colors">
                        <td className="px-6 py-4">
                          <div className="flex items-center gap-3">
                            <div className={`p-2 rounded-lg ${
                              tx.type === 'Income' ? 'bg-emerald-500/10 text-emerald-400' : 
                              tx.type === 'Investment' ? 'bg-amber-500/10 text-amber-400' :
                              'bg-rose-500/10 text-rose-400'
                            }`}>
                              {tx.type === 'Income' ? <TrendingUp size={16} /> : <TrendingDown size={16} />}
                            </div>
                            <span className="font-medium">{tx.name}</span>
                          </div>
                        </td>
                        <td className="px-6 py-4">
                          <span className="px-2.5 py-1 rounded-full bg-white/5 border border-white/10 text-xs text-slate-300">
                            {tx.category}
                          </span>
                        </td>
                        <td className="px-6 py-4 text-slate-400 text-sm">
                          {new Date(tx.date).toLocaleDateString()}
                        </td>
                        <td className="px-6 py-4 font-bold">
                          <span className={tx.type === 'Income' ? 'text-emerald-400' : tx.type === 'Investment' ? 'text-amber-400' : 'text-rose-400'}>
                            {tx.type === 'Income' ? '+' : '-'}${tx.amount.toLocaleString()}
                          </span>
                        </td>
                        <td className="px-6 py-4">
                          <button 
                            onClick={() => deleteTransaction(tx.id)}
                            className="p-2 text-slate-500 hover:text-rose-400 transition-colors opacity-0 group-hover:opacity-100"
                          >
                            <Trash2 size={16} />
                          </button>
                        </td>
                      </tr>
                    ))
                  ) : (
                    <tr>
                      <td colSpan={5} className="px-6 py-12 text-center text-slate-500 italic">
                        No transactions found. Start by adding one above.
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>

        {/* Sidebar / AI Insights */}
        <div className="lg:col-span-4 space-y-8">
          <div className="glass p-6 rounded-3xl">
            <div className="flex items-center gap-2 mb-6">
              <Sparkles className="text-amber-400 animate-pulse" size={24} />
              <h3 className="font-bold text-xl">AI Financial Tips</h3>
            </div>

            <div className="space-y-4">
              {isLoadingTips ? (
                Array.from({ length: 3 }).map((_, i) => (
                  <div key={i} className="animate-pulse bg-white/5 rounded-2xl h-24 w-full"></div>
                ))
              ) : (
                aiTips.map((tip, idx) => (
                  <div key={idx} className="glass-card p-5 rounded-2xl group cursor-default">
                    <div className="flex justify-between items-start mb-2">
                      <h4 className="font-semibold text-amber-100 group-hover:text-amber-300 transition-colors">{tip.title}</h4>
                      <span className={`text-[10px] px-2 py-0.5 rounded-full uppercase tracking-tighter ${
                        tip.priority === 'High' ? 'bg-rose-500/20 text-rose-400 border border-rose-500/30' : 
                        tip.priority === 'Medium' ? 'bg-amber-500/20 text-amber-400 border border-amber-500/30' :
                        'bg-emerald-500/20 text-emerald-400 border border-emerald-500/30'
                      }`}>
                        {tip.priority} Priority
                      </span>
                    </div>
                    <p className="text-slate-400 text-sm leading-relaxed">
                      {tip.advice}
                    </p>
                  </div>
                ))
              )}
            </div>

            <div className="mt-8 p-4 bg-indigo-500/10 border border-indigo-500/20 rounded-2xl text-xs text-indigo-200">
              <div className="flex items-center gap-2 mb-2 font-bold uppercase tracking-widest text-[10px]">
                <AlertCircle size={12} />
                Financial Health Note
              </div>
              Pro tip: You've spent 24% less on Entertainment this week compared to last. That's $120 saved for your investment goal!
            </div>
          </div>

          <div className="glass p-6 rounded-3xl relative overflow-hidden">
            <div className="relative z-10">
              <h3 className="font-bold text-lg mb-4">Total Spending Goal</h3>
              <div className="flex justify-between items-end mb-2">
                <span className="text-slate-400 text-sm">Monthly Budget</span>
                <span className="text-indigo-300 text-lg font-bold">${stats.expenses.toLocaleString()} / $5,000</span>
              </div>
              <div className="w-full bg-white/5 rounded-full h-3 mb-6 overflow-hidden">
                <div 
                  className="bg-indigo-500 h-full rounded-full transition-all duration-1000 shadow-[0_0_10px_rgba(99,102,241,0.5)]"
                  style={{ width: `${Math.min((stats.expenses / 5000) * 100, 100)}%` }}
                ></div>
              </div>
              <p className="text-xs text-slate-500 leading-relaxed italic">
                Tip: If you continue at this pace, you will stay $450 under your budget by the end of the month.
              </p>
            </div>
          </div>
        </div>
      </div>

      {/* Add Transaction Modal */}
      {isAddingTx && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm" onClick={() => setIsAddingTx(false)}></div>
          <div className="relative glass p-8 rounded-[2.5rem] w-full max-w-lg shadow-2xl border border-white/20 animate-in fade-in zoom-in duration-300">
            <h2 className="text-2xl font-bold mb-6 flex items-center gap-3">
              <div className="p-2 bg-indigo-500 rounded-xl">
                <Plus size={20} className="text-white" />
              </div>
              New Transaction
            </h2>

            <form onSubmit={handleAddTransaction} className="space-y-5">
              <div className="grid grid-cols-2 gap-4">
                <button 
                  type="button" 
                  onClick={() => setFormData({...formData, type: 'Expense'})}
                  className={`py-3 rounded-2xl border transition-all ${formData.type === 'Expense' ? 'bg-rose-500 border-rose-400 text-white shadow-lg shadow-rose-500/20' : 'bg-white/5 border-white/10 text-slate-400 hover:bg-white/10'}`}
                >
                  Expense
                </button>
                <button 
                  type="button" 
                  onClick={() => setFormData({...formData, type: 'Income'})}
                  className={`py-3 rounded-2xl border transition-all ${formData.type === 'Income' ? 'bg-emerald-500 border-emerald-400 text-white shadow-lg shadow-emerald-500/20' : 'bg-white/5 border-white/10 text-slate-400 hover:bg-white/10'}`}
                >
                  Income
                </button>
              </div>

              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-1.5 ml-1">Label Name</label>
                <input 
                  required
                  type="text" 
                  placeholder="e.g., Grocery Shopping"
                  className="w-full bg-white/5 border border-white/10 rounded-2xl px-4 py-3 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all"
                  value={formData.name}
                  onChange={(e) => setFormData({...formData, name: e.target.value})}
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-1.5 ml-1">Amount ($)</label>
                  <input 
                    required
                    type="number" 
                    step="0.01"
                    placeholder="0.00"
                    className="w-full bg-white/5 border border-white/10 rounded-2xl px-4 py-3 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all"
                    value={formData.amount}
                    onChange={(e) => setFormData({...formData, amount: e.target.value})}
                  />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-1.5 ml-1">Category</label>
                  <select 
                    className="w-full bg-[#1e1b4b] border border-white/10 rounded-2xl px-4 py-3 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all appearance-none cursor-pointer"
                    value={formData.category}
                    onChange={(e) => setFormData({...formData, category: e.target.value})}
                  >
                    {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
                  </select>
                </div>
              </div>

              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-1.5 ml-1">Date</label>
                <input 
                  required
                  type="date" 
                  className="w-full bg-white/5 border border-white/10 rounded-2xl px-4 py-3 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all"
                  value={formData.date}
                  onChange={(e) => setFormData({...formData, date: e.target.value})}
                />
              </div>

              <div className="flex gap-4 pt-4">
                <button 
                  type="button"
                  onClick={() => setIsAddingTx(false)}
                  className="flex-1 py-4 bg-white/5 hover:bg-white/10 border border-white/10 text-slate-300 rounded-2xl font-bold transition-all"
                >
                  Cancel
                </button>
                <button 
                  type="submit"
                  className="flex-1 py-4 bg-indigo-600 hover:bg-indigo-500 text-white rounded-2xl font-bold transition-all shadow-xl shadow-indigo-600/30"
                >
                  Save Transaction
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

export type Role = 'SUPPORT' | 'ADMIN' | 'CO_AUDITOR' | 'CUSTOMER';
export type TransactionType = 'Income' | 'Expense' | 'Investment';

export interface User {
  id: string;
  username: string;
  password?: string;
  role: Role;
  name: string;
}

export interface Transaction {
  id: string;
  memberName: string;
  amount: number;
  category: string;
  date: string;
  month: string;
  year: string;
  type: TransactionType;
  recordedBy: string;
}

export interface ChatMessage {
  id: string;
  sender: string;
  text: string;
  timestamp: number;
}

export interface AppConfig {
  googleDriveLink: string;
  members: string[];
}

export const MONTHS = [
  'January', 'February', 'March', 'April', 'May', 'June',
  'July', 'August', 'September', 'October', 'November', 'December'
];

export const YEARS = ['2024', '2025', '2026', '2027', '2028'];

export const INITIAL_MEMBERS = [
  "Member 1", "Member 2", "Member 3", "Member 4", "Member 5",
  "Member 6", "Member 7", "Member 8", "Member 9", "Member 10",
  "Member 11", "Member 12", "Member 13", "Member 14", "Member 15",
  "Member 16", "Member 17", "Member 18", "Member 19", "Member 20"
];

export interface AITip {
  title: string;
  advice: string;
  priority: 'High' | 'Medium' | 'Low';
}

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  Plus, Wallet, TrendingUp, TrendingDown, Download, Trash2, 
  Sparkles, User, PieChart as PieChartIcon, BarChart3, Search, 
  CheckCircle2, AlertCircle, MessageSquare, LogOut, Settings, 
  ShieldCheck, Send, ExternalLink, Cloud
} from 'lucide-react';
import { 
  PieChart, Pie, Cell, ResponsiveContainer, Tooltip as RechartsTooltip,
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Legend
} from 'recharts';
import * as XLSX from 'xlsx';
import { 
  Transaction, TransactionType, Role, User as UserType, 
  AppConfig, ChatMessage, MONTHS, YEARS, INITIAL_MEMBERS, AITip 
} from './types';
import { getFinancialTips } from './geminiService';

const COLORS = ['#6366f1', '#10b981', '#f43f5e', '#f59e0b', '#8b5cf6', '#ec4899', '#06b6d4', '#84cc16'];

const App: React.FC = () => {
  // --- AUTH & STATE ---
  const [currentUser, setCurrentUser] = useState<UserType | null>(() => {
    const saved = localStorage.getItem('zenith_current_user');
    return saved ? JSON.parse(saved) : null;
  });

  const [users, setUsers] = useState<UserType[]>(() => {
    const saved = localStorage.getItem('zenith_users');
    return saved ? JSON.parse(saved) : [
      { id: '1', username: 'support', password: 'wayas.it', role: 'SUPPORT', name: 'Support Admin' }
    ];
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('zenith_txs');
    return saved ? JSON.parse(saved) : [];
  });

  const [chatMessages, setChatMessages] = useState<ChatMessage[]>(() => {
    const saved = localStorage.getItem('zenith_chat');
    return saved ? JSON.parse(saved) : [];
  });

  const [config, setConfig] = useState<AppConfig>(() => {
    const saved = localStorage.getItem('zenith_config');
    return saved ? JSON.parse(saved) : { googleDriveLink: '', members: INITIAL_MEMBERS };
  });

  // --- UI STATE ---
  const [isAddingTx, setIsAddingTx] = useState(false);
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [isManagementOpen, setIsManagementOpen] = useState(false);
  const [loginForm, setLoginForm] = useState({ username: '', password: '' });
  const [aiTips, setAiTips] = useState<AITip[]>([]);
  const [chatInput, setChatInput] = useState('');
  const chatEndRef = useRef<HTMLDivElement>(null);

  // --- FORM STATE ---
  const [txForm, setTxForm] = useState({
    memberName: config.members[0],
    amount: '500',
    type: 'Income' as TransactionType,
    month: MONTHS[new Date().getMonth()],
    year: '2025',
    date: new Date().toISOString().split('T')[0],
    category: 'Subscription'
  });

  // --- EFFECTS ---
  useEffect(() => {
    localStorage.setItem('zenith_users', JSON.stringify(users));
    localStorage.setItem('zenith_txs', JSON.stringify(transactions));
    localStorage.setItem('zenith_chat', JSON.stringify(chatMessages));
    localStorage.setItem('zenith_config', JSON.stringify(config));
    if (currentUser) localStorage.setItem('zenith_current_user', JSON.stringify(currentUser));
    else localStorage.removeItem('zenith_current_user');
  }, [users, transactions, chatMessages, config, currentUser]);

  useEffect(() => {
    if (isChatOpen) chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatMessages, isChatOpen]);

  useEffect(() => {
    const fetchTips = async () => {
      const tips = await getFinancialTips(transactions);
      setAiTips(tips);
    };
    if (transactions.length > 0) fetchTips();
  }, [transactions.length]);

  // --- CALCULATIONS ---
  const stats = useMemo(() => {
    const totalIncome = transactions.filter(t => t.type === 'Income').reduce((s, t) => s + t.amount, 0);
    const totalExpense = transactions.filter(t => t.type === 'Expense').reduce((s, t) => s + t.amount, 0);
    const totalInvest = transactions.filter(t => t.type === 'Investment').reduce((s, t) => s + t.amount, 0);
    return {
      currentBalance: totalIncome - totalExpense - totalInvest,
      totalInvestment: totalInvest,
      totalCapital: totalIncome - totalExpense
    };
  }, [transactions]);

  const trendData = useMemo(() => {
    return MONTHS.slice(0, 6).map(m => ({
      name: m.substring(0, 3),
      Collection: transactions.filter(t => t.month === m && t.type === 'Income').reduce((s, t) => s + t.amount, 0),
      Expense: transactions.filter(t => t.month === m && t.type === 'Expense').reduce((s, t) => s + t.amount, 0),
    }));
  }, [transactions]);

  // --- HANDLERS ---
  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const user = users.find(u => u.username === loginForm.username && u.password === loginForm.password);
    if (user) setCurrentUser(user);
    else alert('Invalid credentials');
  };

  const handleLogout = () => setCurrentUser(null);

  const handleAddTx = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser || currentUser.role === 'CUSTOMER') return;

    const newTx: Transaction = {
      id: crypto.randomUUID(),
      memberName: txForm.memberName,
      amount: parseFloat(txForm.amount),
      type: txForm.type,
      month: txForm.month,
      year: txForm.year,
      date: txForm.date,
      category: txForm.category,
      recordedBy: currentUser.username
    };
    setTransactions([newTx, ...transactions]);
    setIsAddingTx(false);
  };

  const sendChatMessage = (e: React.FormEvent) => {
    e.preventDefault();
    if (!chatInput.trim() || !currentUser) return;
    const msg: ChatMessage = {
      id: crypto.randomUUID(),
      sender: currentUser.name,
      text: chatInput,
      timestamp: Date.now()
    };
    setChatMessages([...chatMessages, msg]);
    setChatInput('');
  };

  const exportData = () => {
    const ws = XLSX.utils.json_to_sheet(transactions);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Transactions");
    XLSX.writeFile(wb, "Zenith_Financials.xlsx");
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen flex items-center justify-center p-4">
        <div className="glass p-10 rounded-[2.5rem] w-full max-w-md shadow-2xl border border-white/20">
          <div className="text-center mb-10">
            <div className="inline-flex p-4 rounded-3xl bg-indigo-500/20 mb-4 border border-indigo-500/30">
              <ShieldCheck className="text-indigo-400 w-12 h-12" />
            </div>
            <h1 className="text-3xl font-bold text-white tracking-tight">Zenith Tracker</h1>
            <p className="text-slate-400 mt-2">Sign in to manage financial goals</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-6">
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2 ml-1">Username</label>
              <input 
                className="w-full bg-white/5 border border-white/10 rounded-2xl px-5 py-4 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
                value={loginForm.username}
                onChange={e => setLoginForm({...loginForm, username: e.target.value})}
                placeholder="Enter username"
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2 ml-1">Password</label>
              <input 
                type="password"
                className="w-full bg-white/5 border border-white/10 rounded-2xl px-5 py-4 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
                value={loginForm.password}
                onChange={e => setLoginForm({...loginForm, password: e.target.value})}
                placeholder="••••••••"
              />
            </div>
            <button className="w-full py-4 bg-indigo-600 hover:bg-indigo-500 text-white rounded-2xl font-bold transition-all shadow-xl shadow-indigo-600/30">
              Access Dashboard
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 relative">
      {/* Header */}
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-6">
        <div className="flex items-center gap-4">
          <div className="p-3 rounded-2xl bg-indigo-500/20 glass border border-indigo-500/30">
            <User className="text-indigo-400 w-8 h-8" />
          </div>
          <div>
            <h1 className="text-2xl font-bold">Welcome, {currentUser.name}</h1>
            <p className="text-slate-400 text-sm">Role: <span className="text-indigo-400 font-semibold">{currentUser.role}</span></p>
          </div>
        </div>
        <div className="flex gap-3 w-full md:w-auto">
          {currentUser.role === 'SUPPORT' && (
            <button onClick={() => setIsManagementOpen(true)} className="p-3 rounded-xl glass-card hover:bg-white/10 text-slate-300">
              <Settings size={20} />
            </button>
          )}
          <button onClick={() => setIsChatOpen(!isChatOpen)} className="p-3 rounded-xl glass-card hover:bg-white/10 text-slate-300 relative">
            <MessageSquare size={20} />
            {chatMessages.length > 0 && <span className="absolute top-0 right-0 w-2 h-2 bg-rose-500 rounded-full"></span>}
          </button>
          <button onClick={exportData} className="px-4 py-2.5 rounded-xl glass-card text-sm font-medium hover:bg-white/10 flex items-center gap-2">
            <Download size={18} /> Export
          </button>
          {currentUser.role !== 'CUSTOMER' && (
            <button onClick={() => setIsAddingTx(true)} className="px-6 py-2.5 rounded-xl bg-indigo-600 hover:bg-indigo-500 text-white font-semibold">
              <Plus size={18} className="inline mr-1" /> Entry
            </button>
          )}
          <button onClick={handleLogout} className="p-3 rounded-xl bg-rose-500/10 hover:bg-rose-500/20 text-rose-400 border border-rose-500/20 transition-all">
            <LogOut size={20} />
          </button>
        </div>
      </header>

      {/* Stats */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-10">
        <div className="glass p-6 rounded-3xl group">
          <p className="text-indigo-300 text-sm mb-1">Current Balance</p>
          <h2 className="text-4xl font-bold tracking-tight text-white">৳ {stats.currentBalance.toLocaleString()}</h2>
          <div className="mt-4 text-emerald-400 text-xs font-semibold flex items-center gap-1">
            <Wallet size={14} /> Available Funds
          </div>
        </div>
        <div className="glass p-6 rounded-3xl group">
          <p className="text-amber-300 text-sm mb-1">Invested Capital</p>
          <h2 className="text-4xl font-bold tracking-tight text-white">৳ {stats.totalInvestment.toLocaleString()}</h2>
          <div className="mt-4 text-amber-400 text-xs font-semibold flex items-center gap-1">
            <TrendingUp size={14} /> Working Capital
          </div>
        </div>
        <div className="glass p-6 rounded-3xl bg-indigo-500/5 group">
          <p className="text-emerald-300 text-sm mb-1">Total Net Equity</p>
          <h2 className="text-4xl font-bold tracking-tight text-emerald-400">৳ {stats.totalCapital.toLocaleString()}</h2>
          <div className="mt-4 text-emerald-300/60 text-xs font-semibold flex items-center gap-1">
            <CheckCircle2 size={14} /> Organization Value
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Activity & Charts */}
        <div className="lg:col-span-8 space-y-8">
          <div className="glass p-6 rounded-3xl">
            <div className="flex items-center gap-2 mb-6">
              <BarChart3 className="text-indigo-400" size={20} />
              <h3 className="font-semibold text-lg">Financial Overview (৳)</h3>
            </div>
            <div className="h-[300px]">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={trendData}>
                  <CartesianGrid strokeDasharray="3 3" stroke="#ffffff10" vertical={false} />
                  <XAxis dataKey="name" stroke="#94a3b8" fontSize={12} tickLine={false} axisLine={false} />
                  <YAxis stroke="#94a3b8" fontSize={12} tickLine={false} axisLine={false} />
                  <RechartsTooltip cursor={{ fill: 'rgba(255,255,255,0.05)' }} contentStyle={{ backgroundColor: '#1e1b4b', border: 'none', borderRadius: '12px' }} />
                  <Legend />
                  <Bar dataKey="Collection" fill="#10b981" radius={[4, 4, 0, 0]} />
                  <Bar dataKey="Expense" fill="#f43f5e" radius={[4, 4, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </div>

          <div className="glass rounded-3xl overflow-hidden">
            <div className="p-6 border-b border-white/10 flex justify-between items-center">
              <h3 className="font-semibold text-lg">Detailed Ledger</h3>
              <div className="flex items-center gap-3">
                {config.googleDriveLink && (
                  <a href={config.googleDriveLink} target="_blank" rel="noreferrer" className="flex items-center gap-2 px-3 py-1.5 rounded-full bg-blue-500/10 text-blue-400 border border-blue-500/20 text-xs font-bold hover:bg-blue-500/20 transition-all">
                    <Cloud size={14} /> Drive Backup
                  </a>
                )}
              </div>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="text-slate-400 text-xs uppercase bg-white/5">
                  <tr>
                    <th className="px-6 py-4">Member / Detail</th>
                    <th className="px-6 py-4">Period</th>
                    <th className="px-6 py-4">Type</th>
                    <th className="px-6 py-4">Amount</th>
                    {currentUser.role !== 'CUSTOMER' && <th className="px-6 py-4">Op</th>}
                  </tr>
                </thead>
                <tbody className="divide-y divide-white/5">
                  {transactions.map(tx => (
                    <tr key={tx.id} className="hover:bg-white/5">
                      <td className="px-6 py-4">
                        <div className="font-medium">{tx.memberName}</div>
                        <div className="text-xs text-slate-500">{tx.category}</div>
                      </td>
                      <td className="px-6 py-4 text-sm">{tx.month} {tx.year}</td>
                      <td className="px-6 py-4 uppercase text-[10px] font-bold tracking-widest">
                        <span className={tx.type === 'Income' ? 'text-emerald-400' : tx.type === 'Investment' ? 'text-amber-400' : 'text-rose-400'}>
                          {tx.type}
                        </span>
                      </td>
                      <td className="px-6 py-4 font-bold">৳ {tx.amount.toLocaleString()}</td>
                      {currentUser.role !== 'CUSTOMER' && (
                        <td className="px-6 py-4">
                          <button onClick={() => setTransactions(transactions.filter(t => t.id !== tx.id))} className="text-slate-600 hover:text-rose-500">
                            <Trash2 size={16} />
                          </button>
                        </td>
                      )}
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>

        {/* AI & Chat Sidebar */}
        <div className="lg:col-span-4 space-y-8">
          <div className="glass p-6 rounded-3xl">
            <div className="flex items-center gap-2 mb-6">
              <Sparkles className="text-amber-400 animate-pulse" size={24} />
              <h3 className="font-bold text-xl">AI Insights</h3>
            </div>
            <div className="space-y-4">
              {aiTips.map((tip, idx) => (
                <div key={idx} className="glass-card p-4 rounded-2xl border-l-4 border-l-indigo-500">
                  <h4 className="font-semibold text-white text-sm mb-1">{tip.title}</h4>
                  <p className="text-slate-400 text-xs leading-relaxed">{tip.advice}</p>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>

      {/* Add Transaction Modal */}
      {isAddingTx && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={() => setIsAddingTx(false)}></div>
          <div className="relative glass p-8 rounded-[2.5rem] w-full max-w-lg animate-in zoom-in duration-200">
            <h2 className="text-2xl font-bold mb-6 flex items-center gap-3">
              <Plus className="bg-indigo-500 text-white rounded-lg p-1" /> New Entry
            </h2>
            <form onSubmit={handleAddTx} className="space-y-5">
              <div className="grid grid-cols-2 gap-4">
                <button type="button" onClick={() => setTxForm({...txForm, type: 'Income', amount: '500', category: 'Subscription'})} className={`py-3 rounded-2xl border transition-all ${txForm.type === 'Income' ? 'bg-emerald-500 border-emerald-400 text-white' : 'glass-card text-slate-400'}`}>Income</button>
                <button type="button" onClick={() => setTxForm({...txForm, type: 'Expense', amount: '', category: 'General'})} className={`py-3 rounded-2xl border transition-all ${txForm.type === 'Expense' ? 'bg-rose-500 border-rose-400 text-white' : 'glass-card text-slate-400'}`}>Expense</button>
                <button type="button" onClick={() => setTxForm({...txForm, type: 'Investment', amount: '', category: 'Business'})} className={`py-3 rounded-2xl border transition-all col-span-2 ${txForm.type === 'Investment' ? 'bg-amber-500 border-amber-400 text-white' : 'glass-card text-slate-400'}`}>Investment (Withdraw for Business)</button>
              </div>

              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1.5">Member / Detail</label>
                {txForm.type === 'Income' ? (
                  <select 
                    className="w-full bg-[#1e1b4b] border border-white/10 rounded-2xl px-4 py-3 text-white appearance-none"
                    value={txForm.memberName}
                    onChange={e => setTxForm({...txForm, memberName: e.target.value})}
                  >
                    {config.members.map(m => <option key={m} value={m}>{m}</option>)}
                  </select>
                ) : (
                  <input 
                    className="w-full bg-white/5 border border-white/10 rounded-2xl px-4 py-3 text-white"
                    placeholder="e.g. Office Rent, Business Stock"
                    value={txForm.memberName}
                    onChange={e => setTxForm({...txForm, memberName: e.target.value})}
                  />
                )}
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-1.5">Amount (৳)</label>
                  <input type="number" className="w-full bg-white/5 border border-white/10 rounded-2xl px-4 py-3 text-white" value={txForm.amount} onChange={e => setTxForm({...txForm, amount: e.target.value})} />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-1.5">Month</label>
                  <select className="w-full bg-[#1e1b4b] border border-white/10 rounded-2xl px-4 py-3 text-white appearance-none" value={txForm.month} onChange={e => setTxForm({...txForm, month: e.target.value})}>
