                  </select>
                </div>
              </div>

              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setIsAddingTx(false)} className="flex-1 py-4 glass-card text-slate-300 rounded-2xl font-bold">Cancel</button>
                <button type="submit" className="flex-1 py-4 bg-indigo-600 hover:bg-indigo-500 text-white rounded-2xl font-bold">Save Record</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Support Management Modal */}
      {isManagementOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/80 backdrop-blur-md" onClick={() => setIsManagementOpen(false)}></div>
          <div className="relative glass p-8 rounded-[2.5rem] w-full max-w-2xl overflow-y-auto max-h-[90vh]">
