            <section className="mb-8">
              <h3 className="text-sm font-bold uppercase text-slate-500 mb-4">Cloud Sync (Google Drive)</h3>
              <div className="flex gap-2">
                <input 
                  className="flex-1 bg-white/5 border border-white/10 rounded-xl px-4 py-2 text-sm" 
                  placeholder="Drive Folder/Sheet URL"
                  value={config.googleDriveLink}
                  onChange={e => setConfig({...config, googleDriveLink: e.target.value})}
                />
