            <section className="mb-8">
              <h3 className="text-sm font-bold uppercase text-slate-500 mb-4">Member Directory</h3>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
                {config.members.map((m, i) => (
                  <input 
                    key={i}
                    className="bg-white/5 border border-white/10 rounded-lg px-2 py-1 text-xs" 
                    value={m}
                    onChange={e => {
                      const newM = [...config.members];
                      newM[i] = e.target.value;
                      setConfig({...config, members: newM});
                    }}
                  />
                ))}
              </div>
            </section>

            <section>
              <h3 className="text-sm font-bold uppercase text-slate-500 mb-4">User Accounts</h3>
              <div className="space-y-2">
                {users.map(u => (
                  <div key={u.id} className="flex justify-between items-center p-3 glass-card rounded-xl">
                    <div className="flex gap-4 items-center">
                      <span className="font-bold text-indigo-400">{u.role}</span>
                      <span>{u.name} (@{u.username})</span>
                    </div>
                    {u.username !== 'support' && (
                      <button onClick={() => setUsers(users.filter(usr => usr.id !== u.id))} className="text-rose-500"><Trash2 size={16} /></button>
                    )}
                  </div>
                ))}
                <button 
                  onClick={() => {
                    const name = prompt('Name:');
                    const user = prompt('Username:');
                    const pass = prompt('Password:');
                    const role = prompt('Role (ADMIN/CO_AUDITOR/CUSTOMER):') as Role;
