                      setUsers([...users, { id: crypto.randomUUID(), name, username: user, password: pass, role }]);
                    }
                  }}
                  className="w-full py-2 border border-dashed border-white/20 rounded-xl text-xs text-slate-500 hover:text-white transition-all"
                >
                  + Add System User
                </button>
              </div>
            </section>
          </div>
